var ERROR_FILTER = JSON.stringify(
		{
			error: {
				code: "400",
				value: "Request is missing a valid $filter query option"
			}
		}
);

//////////////////////////////////////////////////////////////////////////////////////////
//
//	Helper methods
//
//////////////////////////////////////////////////////////////////////////////////////////

var messageLog;

/**
 * Extract all Ids sent by hybris Marketing.
 * @param filter OData $filter provided by hybris Marketing
 * @return All Ids contained in that filter
 */
function getIds(filter) {
	var reg = new RegExp("ServerCampaignId\\seq\\s'(.+?)'", "g");
	var match;
	var result = [];
	while ((match = reg.exec(filter)) !== null) {
		result.push(match[1]);
	}
	return result;
}

/**
 * Extract KeyPartXId and KeyPartXValue from the $filter for a given X.
 * @param filter OData $filter provided by hybris Marketing
 * @param part Integer X
 * @return Object in the form of { Id: "...", Value: "..." }
 */
function getKeyPart(filter, part) {
	var regId = new RegExp("KeyPart" + part + "Id\\seq\\s'(.+?)'");
	var regVal = new RegExp("KeyPart" + part + "Value\\seq\\s'(.+?)'");
	var matchId = regId.exec(filter);
	var matchVal = regVal.exec(filter);
	var result;
	if (matchId === null || matchId[1] === null || matchVal[1] === null) {
		result = null;
	} else {
		result = {
			id: matchId[1],
			value: matchVal[1]
		}
	}
	return result;
}

/**
 * Convert the given Date-Object to the OData string representation.
 * @param date A Javascript Date-Object
 * @returns {String} OData string representation of that date
 */
function dateToString(date) {
	return "\/Date(" + Math.floor(date.getTime()).toString() + ")\/";
}

/**
 * Convert the given ISO8601 Date string to a Javascript Date-Object.
 * @param isoString String in the form of YYYY-MM-DDTHH:mm:ss[Z]
 * @returns {Date} 
 */
function isoStringToDate(isoString) {
	var str = (isoString.slice(-1) === "Z") ? isoString.slice(0, -1) : isoString;
	return new Date(str + ".000Z");
}

function getPaging(sHeader) {
    var oTopMatch = sHeader.match(/\$top=(\d+?)(&|$)/),
        oSkipMatch = sHeader.match(/\$skip=(\d+?)(&|$)/),
        oResult = {};

    if (oTopMatch !== null) {
        oResult.top = parseInt(oTopMatch[1]);
    } else {
        oResult.top = -1;
    }
    if (oSkipMatch !== null) {
        oResult.skip = parseInt(oSkipMatch[1]);
    } else {
        oResult.skip = 0;
    }
    messageLog.setStringProperty("top", oResult.top);
    messageLog.setStringProperty("skip", oResult.skip);
    return oResult;
}

//////////////////////////////////////////////////////////////////////////////////////////
//
//    Process Data method
//
//////////////////////////////////////////////////////////////////////////////////////////

function processData(message) {

	messageLog = messageLogFactory.getMessageLog(message);

	var headers = message.getHeaders();
	var request = headers.get("CamelHttpQuery");

	// Regular expression to extract the filter query
	var reg = new RegExp("(\\$|%24)filter=(.+?)(&|$)");
	var match = reg.exec(request);
	var filter = "";
	if (match !== null) {
		filter = match[2];
	}

	// Verify that the query contains a valid "$filter"
	if (filter.length === 0) {		
	    headers.put("ErrorResponseDetail",  ERROR_FILTER);
	    message.setBody(ERROR_FILTER);
	    throw ERROR_FILTER;
	}
	filter = decodeURIComponent(filter);
	message.setProperty("QueryFilter", filter);

	//Get the requested Advertisers
	var sKeyBase = "KeyPart",
	oKeyRegExp = new RegExp(sKeyBase + "2" + "Value eq '[^']+?'"),
	oMatch = oKeyRegExp.exec(filter);
	var aResult = [];
	if (oMatch !== null) {
		var fields = oMatch[0].split('eq');
		var advertiser = fields[1].replace(/'/g,"").trim();
	}

	//Get pagination parameters	
	var oPaging = getPaging(decodeURIComponent(request).toString());

	//Get filter for campaign Name
	var campaignNameFilter = "substringof\\('[^']+?', CampaignName \\)";
	var sRequest = decodeURIComponent(request);
	var cmpgFilterRegExp = new RegExp(campaignNameFilter);
	oMatch = cmpgFilterRegExp.exec(sRequest);
	campaignNameSearch = "";
	if (oMatch !== null) {
		var searchFields = oMatch[0].split(',');
		campaignNameSearch = searchFields[0].replace( 'substringof(', '' );
		campaignNameSearch = campaignNameSearch.replace( /['"]+/g, '' );
	}

	//Prepare request
	var request = {
			request: {
				advertiser :  advertiser,
				campaignNameSearch: campaignNameSearch,
				nextPageToken : oPaging.skip,
				pageSize : oPaging.top

			}
	};

	message.setBody(JSON.stringify(request));

	headers.clear();
	headers.put("Content-Type", "application/json")

	return message;
}

