function processData(message) {
  var body = message.getBody(new java.lang.String().getClass());
  body = JSON.parse(body);
  var messageLog = messageLogFactory.getMessageLog(message);
  var logBody = message.getProperty('LogMessageBody');
  if (messageLog && logBody && logBody.equalsIgnoreCase('yes')) {
    messageLog.addAttachmentAsString('getProjectResponse:', JSON.stringify(body, undefined, 4), 'text/json');
  }
  var existingProject = false;
  if (body.d && body.d[0].projectDetails) {
    // create Project
    message.setProperty('ExistingProject', 'true');
    existingProject = true;
  } else {
    // update project
    message.setProperty('ExistingProject', 'false');
  }

  var statusToSync = String(message.getProperty('ProjectSyncOnlyOpenProjects'));
  var projectJSON = String(message.getProperty('projectJSON'));
  var project = JSON.parse(projectJSON);
  project = project.Project;

  var stage = project.StageDesc;

  if (statusToSync.indexOf(stage) !== -1) {
    message.setProperty('SyncProject', 'yes');
  } else if (existingProject) {
    message.setProperty('SyncProject', 'yes');
  } else {
    message.setProperty('SyncProject', 'no');
  }

  return message;
}

