function getValue(tag, xmlString) {
  var value = null;
  var startPos = null;
  var endPos = null;
  var startTag = '<' + tag + '>';
  var endTag = '</' + tag + '>';
  var tempString = xmlString;
  startPos = tempString.search(startTag) + startTag.length;
  endPos = tempString.search(endTag);
  value = tempString.slice(startPos, endPos);
  return value;
}

