function xsdDatetimeToJS(sDate) {
    if (sDate.indexOf("Z") !== (sDate.length - 1)) {
        sDate += "Z";
    }
    return sDate.replace(/\-/g,'\/').replace(/T/,' ').replace(/Z/,' -0');
}

function getDateRange(sFilter) {
