    	oMatch = getIds(sFilter);
        if (oMatch.length === 0) {
        	oHeaders.put("ErrorResponseDetail", ERROR_IDS);
    	    message.setBody(ERROR_IDS);
    	    throw ERROR_IDS;
        }

    	// Create Success Data for every Id
    	sIds = [];
    	aData = [];
