  }
  value = tempString.slice(startPos, endPos);
  return value;
}

function getAllIndexes(arr, val) {
  var indexes = [];
  var i = -1;
  while ((i = arr.indexOf(val, i + 1)) !== -1) {
    indexes.push(i);
  }
  return indexes;
}

