        	    billItems[item].sourceItems[creditItemIndex].creditedQuantity.value = -1 * billItems[item].sourceItems[creditItemIndex].creditedQuantity.value;
        	    billItems[item].sourceItems[creditItemIndex].includedQuantity.value = -1 * billItems[item].sourceItems[creditItemIndex].includedQuantity.value;
        	}
        }
        else {
        	singleBill.BillList.Bills.billingType = "CHARGE";
        	billItems[item].sourceItems = billItems[item].charges;
        }
    }

    // Rename usageRecords properties
    renameUsageRecordsProperties(singleBill);

    body = JSON.stringify(singleBill);
    message.setBody(body);
    return message;
}

function renameUsageRecordsProperties(obj) {
    if (Array.isArray(obj)) {
        obj.forEach(renameUsageRecordsProperties);
    } else if (obj && typeof obj === 'object') {
        Object.keys(obj).forEach(function(key) {
            if (key === 'usageRecords@nextLink') {
                obj['usageRecords_nextLink'] = obj[key];
                delete obj[key];
            } else if (key === 'usageRecords@count') {
                obj['usageRecords_count'] = obj[key];
                delete obj[key];
            }
            renameUsageRecordsProperties(obj[key]);
        });
    }
}

